#!/usr/bin/env pwsh\n\n# InsureXThon Azure Deployment Script\n# This script automates the complete Azure setup\n\nparam(\n    [string]$SubscriptionId,\n    [string]$ResourceGroup = \"rg-insurexthon\",\n    [string]$Location = \"eastus\",\n    [string]$AppName = \"insurexthon\",\n    [string]$Environment = \"prod\"\n)\n\n# Color output helpers\nfunction Write-Header { Write-Host \"\\n=== $args ===\" -ForegroundColor Cyan }\nfunction Write-Success { Write-Host \"✓ $args\" -ForegroundColor Green }\nfunction Write-Error { Write-Host \"✗ $args\" -ForegroundColor Red }\nfunction Write-Warning { Write-Host \"⚠ $args\" -ForegroundColor Yellow }\n\nWrite-Header \"InsureXThon Azure Deployment\"\n\n# 1. Authenticate with Azure\nWrite-Header \"Step 1: Azure Authentication\"\ntry {\n    $account = az account show --query \"id\" -o tsv\n    if (-not $account) {\n        Write-Host \"Logging in to Azure...\"\n        az login\n        if ($SubscriptionId) {\n            az account set --subscription $SubscriptionId\n        }\n    }\n    Write-Success \"Authenticated with Azure\"\n}\ncatch {\n    Write-Error \"Azure authentication failed: $_\"\n    exit 1\n}\n\n# 2. Create Resource Group\nWrite-Header \"Step 2: Create Resource Group\"\ntry {\n    $rgExists = az group exists --name $ResourceGroup --query \"value\" -o tsv\n    if ($rgExists -eq \"true\") {\n        Write-Warning \"Resource group '$ResourceGroup' already exists\"\n    }\n    else {\n        az group create --name $ResourceGroup --location $Location\n        Write-Success \"Created resource group: $ResourceGroup\"\n    }\n}\ncatch {\n    Write-Error \"Failed to create resource group: $_\"\n    exit 1\n}\n\n# 3. Create Azure Entra ID App Registration\nWrite-Header \"Step 3: Create Entra ID App Registration\"\ntry {\n    $appName = \"$AppName-api\"\n    $existingApp = az ad app list --filter \"displayName eq '$appName'\" --query \"[0].appId\" -o tsv\n    \n    if ($existingApp) {\n        Write-Warning \"App registration '$appName' already exists: $existingApp\"\n        $appId = $existingApp\n    }\n    else {\n        $appId = az ad app create --display-name $appName --query \"appId\" -o tsv\n        Write-Success \"Created app registration: $appId\"\n    }\n    \n    # Create client secret\n    $secret = az ad app credential create --id $appId --years 2 --query \"password\" -o tsv\n    Write-Success \"Created client secret (valid 2 years)\"\n    Write-Warning \"Save this client secret securely: $secret\"\n}\ncatch {\n    Write-Error \"Failed to create app registration: $_\"\n    exit 1\n}\n\n# 4. Create Azure Key Vault\nWrite-Header \"Step 4: Create Azure Key Vault\"\ntry {\n    $kvName = \"kv-$appName\"\n    $kvExists = az keyvault list --query \"[?name=='$kvName'].name\" -o tsv\n    \n    if ($kvExists) {\n        Write-Warning \"Key vault '$kvName' already exists\"\n    }\n    else {\n        az keyvault create --resource-group $ResourceGroup --name $kvName --location $Location\n        Write-Success \"Created Key Vault: $kvName\"\n    }\n}\ncatch {\n    Write-Error \"Failed to create Key Vault: $_\"\n    # Continue - Key Vault creation might fail due to naming conflicts\n}\n\n# 5. Deploy Infrastructure with Bicep\nWrite-Header \"Step 5: Deploy Infrastructure (Bicep)\"\ntry {\n    Write-Host \"Validating Bicep template...\"\n    az deployment group validate `\n        --resource-group $ResourceGroup `\n        --template-file \"infra/main.bicep\" `\n        --parameters appName=$AppName location=$Location environment=$Environment\n    \n    Write-Success \"Bicep template validation passed\"\n    \n    Write-Host \"Deploying infrastructure...\"\n    $deployment = az deployment group create `\n        --resource-group $ResourceGroup `\n        --template-file \"infra/main.bicep\" `\n        --parameters appName=$AppName location=$Location environment=$Environment `\n        --query \"properties.outputs\"\n    \n    Write-Success \"Infrastructure deployment completed\"\n    Write-Host $deployment | ConvertFrom-Json | ConvertTo-Json -Depth 10\n}\ncatch {\n    Write-Error \"Failed to deploy infrastructure: $_\"\n    exit 1\n}\n\n# 6. Configure GitHub Secrets\nWrite-Header \"Step 6: GitHub Secrets Configuration\"\nWrite-Warning \"Please add these secrets to your GitHub repository:\"\nWrite-Host @\"\n\n1. Go to: https://github.com/AkshayUsha/Create-a-WeCAT-Portfolio-Stress-Test-Reinsurance-Placement-Optimiser\n2. Settings → Secrets and variables → Actions\n3. Add these secrets:\n\nAZURE_CREDENTIALS:\n{\n  \"clientId\": \"$appId\",\n  \"clientSecret\": \"$secret\",\n  \"subscriptionId\": \"$SubscriptionId\",\n  \"tenantId\": \"$(az account show --query 'tenantId' -o tsv)\"\n}\n\nAZURE_SUBSCRIPTION_ID: $SubscriptionId\nAZURE_TENANT_ID: $(az account show --query 'tenantId' -o tsv)\nAZURE_CLIENT_ID: $appId\nAZURE_CLIENT_SECRET: $secret\nAZURE_RESOURCE_GROUP: $ResourceGroup\nAZURE_APP_SERVICE_NAME: $appName-api\nAZURE_STATIC_WEB_APP_NAME: $appName-web\nAZURE_OPENAI_API_KEY: <your-openai-key>\nAZURE_OPENAI_ENDPOINT: <your-openai-endpoint>\n\"@\n\n# 7. Get Deployment Outputs\nWrite-Header \"Step 7: Deployment Outputs\"\ntry {\n    $outputs = az deployment group show `\n        --resource-group $ResourceGroup `\n        --name main `\n        --query \"properties.outputs\" -o json | ConvertFrom-Json\n    \n    Write-Success \"Deployment completed successfully!\"\n    Write-Host $outputs | ConvertTo-Json -Depth 10\n}\ncatch {\n    Write-Warning \"Could not retrieve deployment outputs\"\n}\n\n# 8. Verify Deployment\nWrite-Header \"Step 8: Verify Deployment\"\ntry {\n    $resources = az resource list --resource-group $ResourceGroup --query \"length(@)\" -o tsv\n    Write-Success \"Created $resources resources in $ResourceGroup\"\n    \n    # List all created resources\n    Write-Host \"\\nCreated Resources:\"\n    az resource list --resource-group $ResourceGroup --query \"[].{Name:name, Type:type}\" -o table\n}\ncatch {\n    Write-Warning \"Could not verify deployment\"\n}\n\nWrite-Header \"Deployment Complete!\"\nWrite-Success \"Your Azure infrastructure is ready for deployment\"\nWrite-Host @\"\n\nNext steps:\n1. Configure GitHub secrets (see above)\n2. Push code to main branch to trigger CI/CD\n3. Monitor deployment in GitHub Actions\n4. Verify endpoints are accessible\n\nUseful commands:\n  # View logs\n  az webapp log tail --resource-group $ResourceGroup --name $appName-api\n  \n  # Check health\n  curl https://$appName-api.azurewebsites.net/health\n  \n  # View resource group\n  az resource list --resource-group $ResourceGroup -o table\n\"@\n"